    private final String value;
    private final String displayName;
    private final String banglaName;
    private final String description;

    Permission(String value, String displayName, String banglaName, String description) {
        this.value = value;
        this.displayName = displayName;
        this.banglaName = banglaName;
        this.description = description;
    }

    public String getValue() {
        return value;
    }

    public String getDisplayName() {
        return displayName;
    }

    public String getBanglaName() {
        return banglaName;
    }

    public String getDescription() {
        return description;
    }

    public static Permission fromString(String value) {
        for (Permission permission : Permission.values()) {
            if (permission.value.equalsIgnoreCase(value)) {
                return permission;
            }
        }
        throw new IllegalArgumentException("No constant with value " + value + " found");
    }
    public PermissionResponse toResponse() {
        return new PermissionResponse(
                value,
                displayName,
                banglaName,
                description
        );
    }

